import math

_input_call_count = 0
n = 10  # default test data scale

def generate_input(n):
    global _input_call_count
    _input_call_count += 1
    if _input_call_count == 1:
        a = max(1, int(n) + 1)
        v = max(a, int(n) + 5)
        return f"{a} {v}"
    else:
        l = max(1, int(n) * 2)
        d = max(0, int(n))
        w = max(1, int(n) // 2 + 1)
        return f"{l} {d} {w}"

def getdt():
    return map(int, generate_input(n).split())

def calc(v0, v, a, x):
    t = (v - v0) / a
    x0 = v0 * t + 0.5 * a * t * t
    if x0 >= x:
        return (x, (math.sqrt(v0 * v0 + 2 * a * x) - v0) / a)
    return (x0, t)

def go(v0, v, a, x):
    x0, t = calc(v0, v, a, x)
    return t + (x - x0) / v

a, v = getdt()
l, d, w = getdt()
if w > v:
    w = v
x, t = calc(0, w, a, d)
if x == d:
    print(go(0, v, a, l))
else:
    print(t + go(w, v, a, (d - x) * 0.5) * 2 + go(w, v, a, l - d))
